text:
{
  "formal_minutes": {
    "decisions": {
      "confirmed": [
        "공개 릴리스 타깃은 smoke 테스트 통과를 전제로 금요일 15:00 KST로 확정된다.",
        "packageName 불일치가 발생한 경우 스크립트를 무시하지 않고, 먼저 패키지 설정/컨트랙트를 점검한 뒤 컨트랙트 자체의 오류 여부를 판단한다."
      ],
      "rejected_proposals": [
        "Hara의 \"smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경\" 제안은 최종 합의에서 반려됨."
      ],
      "internal_stretch_goals": [
        "수요일 릴리스는 내부 stretch goal로만 유지하며, 공개 릴리스 목표로 확정되지 않음."
      ]
    },
    "non_decisions": [
      "README 설치 단계 검토의 책임자와 구체적 소유자가 미정이다.",
      "README 검토의 정확한 마감 시한은 ‘목요일 가능 시’로만 언급됨.",
      "Hara의 tarball 경로 확인 완료 기한은 미정이며, Minjun 결과 공유 후 진행으로만 정리됨.",
      "릴리스 노트에 내부 stretch goal(수요일)을 언급할지 여부는 미정."
    ],
    "risks": [
      "생성된 tarball 경로가 잘못되면 릴리스가 지연될 수 있음.",
      "README 설치 단계가 오래된 내용이면 릴리스 노트/안내가 사용자에게 오도될 수 있음."
    ],
    "open_questions": [
      "최종 공개 릴리스 승인 권한자는 누구인가?",
      "릴리스 노트에 내부 stretch goal(수요일)을 포함할 것인지?"
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "smoke 테스트 재실행 후 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "높음"
    },
    {
      "owner": "Doyun",
      "task": "실패 트리아지 노트를 action_items.md에 작성",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "높음"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 smoke 결과 공유 후 생성 tarball 경로 확인",
      "due": "Minjun 결과 공유 이후",
      "status": "확정",
      "source_certainty": "높음"
    },
    {
      "owner": "미지정",
      "task": "README 설치 단계 최신성 검토",
      "due": "목요일(가능 시)",
      "status": "소유자 및 기한 확정 필요",
      "source_certainty": "중간"
    }
  ],
  "followup_note": {
    "check_next": [
      "금요일 10:00 KST 이전에 Minjun의 smoke 테스트 결과가 공유되었는지 확인한다.",
      "해당 결과 기반으로 공개 릴리스 Gate(금요일 15:00 KST)가 유지 가능한지 확인한다.",
      "Doyun의 실패 트리아지 노트가 action_items.md에 작성되었는지 검증한다.",
      "Hara의 tarball 경로 점검이 완료되었는지 확인한다.",
      "README install steps의 최신성 점검 담당자와 확정 기한을 별도 확정한다."
    ],
    "do_not_invent": [
      "고객명/파트너명, 예산, 보안 사고, 장애, 법무 승인 요건, 임의의 owner 또는 deadline를 추가로 가정하지 않는다.",
      "회의록에 없는 승인권자, 법적 판단, 조직적 제재 관련 정보를 추론해 추가하지 않는다.",
      "수요일을 공개 릴리스 확정일로 오해하여 기록하지 않는다."
    ]
  },
  "non_invention_rules": [
    "회의록의 명시적 정보만 사용하고, 누락된 항목(고객/예산/보안/장애/법무/owner/deadline)은 추정 금지.",
    "제안이 반려된 내용과 확정된 내용을 명확히 구분한다.",
    "내부 stretch goal을 공개 릴리스 결정사항으로 재해석하지 않는다.",
    "Open/확정된 날짜 표현(금/수/목 요일 및 KST 기준 명시 시각) 외의 정밀 일정 생성 금지."
  ]
}
